import { Link } from "react-router-dom";
import devolver from '../assets/images/devolver.png';
import { useEffect, useState } from "react";
import NavbarGestionSalas from "../components/NavbarGestionSalas";
import "../styles/EditarEstado.css";
import axios from "axios";

function EditarEstado() {
  const [salas, setSalas] = useState([]);
  const [salaSeleccionada, setSalaSeleccionada] = useState(null);
  const [estado, setEstado] = useState("");

  // 🔥 FUNCIÓN PARA TRAER SALAS
  const obtenerSalas = async () => {
    try {
      const res = await axios.get("http://localhost:3001/api/salas");
      setSalas(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  // 🔥 CARGAR AL INICIO
  useEffect(() => {
    obtenerSalas();
  }, []);

  // 🔹 Seleccionar sala
  const seleccionarSala = (sala) => {
    setSalaSeleccionada(sala);
    setEstado(sala.estado);
  };

  // 🔹 Actualizar estado
  const actualizarEstado = async () => {
    if (!salaSeleccionada) return alert("Selecciona una sala");

    try {
      await axios.put(
        `http://localhost:3001/api/salas/${salaSeleccionada.id}`,
        { estado: estado.toLowerCase() }
      );

      alert("Estado actualizado ✅");

      // 🔥 refrescar lista
      await obtenerSalas();

      // limpiar selección
      setSalaSeleccionada(null);
      setEstado("");

    } catch (error) {
      console.error(error);
      alert("Error al actualizar ❌");
    }
  };

  return (
    <div className="container">
      <NavbarGestionSalas />

      <div className="content">

        {/* IZQUIERDA */}
        <div className="formSection">
          <h2>Sala N° {salaSeleccionada?.id || ""}</h2>

          <div className="formGroup">
            <label>Estado:</label>
            <select
              value={estado}
              onChange={(e) => setEstado(e.target.value)}
            >
              <option value="">Seleccione</option>
              <option value="disponible">Disponible</option>
              <option value="ocupado">Ocupado</option>
              <option value="mantenimiento">Mantenimiento</option>
            </select>
          </div>

          <button className="actualizarBtn" onClick={actualizarEstado}>
            Actualizar
          </button>
        </div>

        {/* DERECHA */}
        <div className="listSection">

          {salas.length === 0 ? (
            <div className="emptyState">
              <p>Aquí se mostrarán las salas creadas</p>
            </div>
          ) : (
            salas.map((s) => (
              <div key={s.id} className="formGroup salaCard">

                <div className="salaHeader">
                  <h3 className="salaTitulo">{s.nombre}</h3>
                </div>

                <div className="salaInfo">
                  <p><strong>ID:</strong> {s.id}</p>
                  <p><strong>Ubicación:</strong> {s.ubicacion}</p>
                  <p><strong>Capacidad:</strong> {s.capacidad}</p>
                  <p><strong>Facultad:</strong> {s.facultad_id}</p>
                </div>

                <span className={`estado ${s.estado}`}>
                  {s.estado}
                </span>

              </div>
            ))
          )}

        </div>

      </div>

      {/* FOOTER */}
      <div className="footer">
        <Link to="/inicio/GSInicio"> <img src={devolver} alt="devolver" className="devolver" /></Link>
      </div>
    </div>
  );
}

export default EditarEstado;
